void BaxterLeftArmModel::EvaluatedJdq(CMAT::Matrix* dJdq)
{
	//ortos::DebugConsole::Write(ortos::LogLevel::notice, "ArmModel::EvaluatedJdq", "Using Baxter Left Arm Model!");

    double q[7], out1[42], out2[42], out3[42], out4[42], out5[42], out6[42], out7[42];

    for (int i = 0; i < 7; i++)
    {
        q[i] = q_(i + 1);
    }

    EvaluatedJdq(q, out1, out2, out3, out4, out5, out6, out7);

    dJdq[0] = CMAT::Matrix(6, 7, out1);
    dJdq[1] = CMAT::Matrix(6, 7, out2);
    dJdq[2] = CMAT::Matrix(6, 7, out3);
    dJdq[3] = CMAT::Matrix(6, 7, out4);
    dJdq[4] = CMAT::Matrix(6, 7, out5);
    dJdq[5] = CMAT::Matrix(6, 7, out6);
    dJdq[6] = CMAT::Matrix(6, 7, out7);
}

